import type { InputStream } from '@lezer/lr';

/**
 * Get the actual text with the specified length, starting at the stream's current position.
 * @internal
 */
export function getTextFromStream(
  inputStream: InputStream,
  maxCharacters: number,
): string {
  let text = '';
  let nextPeek = 0;
  while (nextPeek < maxCharacters && inputStream.peek(nextPeek) !== -1) {
    text += String.fromCharCode(inputStream.peek(nextPeek));
    nextPeek += 1;
  }

  return text;
}
